#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        char diamonds[N][M];
        for (int i = 0; i < N; i++) {
            scanf("%s", diamonds[i]);
        }
        int maxOn = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int on = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if (((mask >> i) & 1) == 0) {
                        if (diamonds[i][j] == '*') {
                            on++;
                        }
                    } else {
                        if (diamonds[i][j] == '.') {
                            on++;
                        }
                    }
                }
            }
            if (__builtin_popcount(mask) <= K) {
                maxOn = (on > maxOn) ? on : maxOn;
            }
        }
        printf("%d\n", maxOn);
    }
    return 0;
}

