    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K = sc.nextInt();
            char[][] diamonds = new char[N][M];
            for (int i = 0; i < N; i++) {
                diamonds[i] = sc.next().toCharArray();
            }
            int maxOn = 0;
            for (int mask = 0; mask < (1 << N); mask++) {
                int on = 0;
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < M; j++) {
                        if (((mask >> i) & 1) == 0) {
                            if (diamonds[i][j] == '*') {
                                on++;
                            }
                        } else {
                            if (diamonds[i][j] == '.') {
                                on++;
                            }
                        }
                    }
