const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++];

for (let i = 0; i < +input(); i++) {
    let [N, M, K] = input().split(' ').map(Number);
    let diamonds = [];
    for (let j = 0; j < N; j++) {
        diamonds.push(input().split(''));
    }
    let maxOn = 0;
    for (let mask = 0; mask < (1 << N); mask++) {
        let on = 0;
        for (let j = 0; j < N; j++) {
            for (let k = 0; k < M; k++) {
                if (((mask >> j) & 1) === 0) {
                    if (diamonds[j][k] === '*') {
                        on++;
                    }
                } else {
                    if (diamonds[j][k] === '.') {
                        on++;
                    }
                }
            }
        }
        if (countBits(mask) <= K) {
            maxOn = Math.max(on, maxOn);
        }
    }
    console.log(maxOn);
}

function countBits(n) {
    let count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}
